INSERT INTO `frontends` VALUES (1,'seo.data','{\"seo_image\":\"1\",\"keywords\":[\"quotematch\",\"freelancing\",\"bid\",\"job post\",\"bid project\",\"earning\",\"viserlab\"],\"description\":\"QuoteMatch is a dynamic freelancing platform connecting clients with skilled professionals across various industries. With secure transactions, a user-friendly interface, and advanced project management tools, QuoteMatch simplifies remote work and collaboration.\",\"social_title\":\"Global Freelancing Marketplace\",\"social_description\":\"QuoteMatch is a dynamic freelancing platform connecting clients with skilled professionals across various industries. With secure transactions, a user-friendly interface, and advanced project management tools, QuoteMatch simplifies remote work and collaboration.\",\"image\":\"679de5c787bc51738401223.png\"}',NULL,NULL,'','2020-07-04 23:42:52','2026-06-17 14:35:19'),(24,'about.content','{\"has_image\":\"1\",\"heading\":\"Simple and Easy to Find Freelancer or Great Job\",\"image\":\"67d931272de8c1742287143.png\"}',NULL,'basic','','2020-10-28 00:51:20','2025-03-18 02:39:03'),(25,'blog.content','{\"heading\":\"Our Latest Blog Post\",\"subheading\":\"Stay updated with the latest insights, tips, and trends from our expert team.\"}',NULL,'basic','','2020-10-28 00:51:34','2025-03-18 04:04:41'),(27,'contact_us.content','{\"heading\":\"Let`s Talk with US\",\"subheading\":\"Disregard the old standards. You can have the best individuals. At this moment. Here.\",\"title\":\"Contact with Us\",\"email_address\":\"democompany@gmail.com\",\"contact_number\":\"+1-666-0121\",\"contact_details\":\"2118 Thornridge Cir. Syracuse\"}',NULL,'basic','','2020-10-28 00:59:19','2025-01-30 03:08:10'),(28,'counter.content','{\"heading\":\"Latest News\",\"subheading\":\"Lorem ipsum dolor sit, amet consectetur adipisicing elit. Doloribus necessitatibus repudiandae porro reprehenderit, beatae perferendis repellat quo ipsa omnis, vitae!\"}',NULL,'basic',NULL,'2020-10-28 01:04:02','2024-03-13 23:54:07'),(31,'social_icon.element','{\"title\":\"Facebook\",\"social_icon\":\"<i class=\\\"fab fa-facebook-f\\\"><\\/i>\",\"url\":\"https:\\/\\/www.facebook.com\\/\"}',NULL,'basic','','2020-11-12 04:07:30','2024-11-18 23:33:42'),(33,'feature.content','{\"heading\":\"asdf\",\"sub_heading\":\"asdf\"}',NULL,'basic',NULL,'2021-01-03 23:40:54','2021-01-03 23:40:55'),(34,'feature.element','{\"title\":\"asdf\",\"description\":\"asdf\",\"feature_icon\":\"asdf\"}',NULL,'basic',NULL,'2021-01-03 23:41:02','2021-01-03 23:41:02'),(35,'service.element','{\"trx_type\":\"withdraw\",\"service_icon\":\"<i class=\\\"las la-highlighter\\\"><\\/i>\",\"title\":\"asdfasdf\",\"description\":\"asdfasdfasdfasdf\"}',NULL,'basic',NULL,'2021-03-06 01:12:10','2021-03-06 01:12:10'),(36,'service.content','{\"trx_type\":\"deposit\",\"heading\":\"asdf fffff\",\"subheading\":\"555\"}',NULL,'basic',NULL,'2021-03-06 01:27:34','2022-03-30 08:07:06'),(41,'cookie.data','{\"short_desc\":\"We use cookies to improve your experience, remember preferences, and analyse site traffic.\",\"description\":\"<h4>Cookie Policy<\\/h4>\\n<p>QuoteMatch uses essential and analytics cookies to keep you signed in, remember consent choices, and improve the marketplace experience.<\\/p>\\n<h4>Essential cookies<\\/h4>\\n<p>These cookies are required for login sessions, security tokens, and remembering your cookie consent choice.<\\/p>\\n<h4>Analytics cookies<\\/h4>\\n<p>We may use analytics cookies to understand how visitors use public pages and dashboards. These are only set when you allow cookies.<\\/p>\\n<h4>Managing cookies<\\/h4>\\n<p>You can accept or reject non-essential cookies using the banner on your first visit. You can also clear cookies through your browser settings.<\\/p>\\n<h4>Contact<\\/h4>\\n<p>For privacy questions, contact us via the Contact page or review our Privacy Policy.<\\/p>\",\"status\":1}',NULL,'basic',NULL,'2020-07-04 23:42:52','2026-07-06 19:02:01'),(42,'policy_pages.element','{\"title\":\"Privacy Policy\",\"details\":\"<h4>Introduction<\\/h4>\\n<p>QuoteMatch respects your privacy and processes personal data in line with UK GDPR and the Data Protection Act 2018.<\\/p>\\n<h4>Data we collect<\\/h4>\\n<ul>\\n<li>Account details such as name, email, phone, and business information<\\/li>\\n<li>Request and quote content you submit on the platform<\\/li>\\n<li>Messages, reviews, verification documents, and support tickets<\\/li>\\n<li>Technical data such as IP address, browser type, and cookie preferences<\\/li>\\n<\\/ul>\\n<h4>How we use data<\\/h4>\\n<p>We use your information to operate the marketplace, match requests with providers, send service notifications, improve security, and comply with legal obligations.<\\/p>\\n<h4>Your rights<\\/h4>\\n<p>You may request access, correction, deletion, or restriction of your personal data. Contact us using the details on our Contact page.<\\/p>\\n<h4>Retention<\\/h4>\\n<p>We retain account and transaction records only for as long as needed to provide the service, resolve disputes, and meet legal requirements.<\\/p>\"}','{\"image\":null,\"description\":null,\"social_title\":null,\"social_description\":null,\"keywords\":null}','basic','privacy-policy','2021-06-09 08:50:42','2026-07-06 19:02:01'),(43,'policy_pages.element','{\"title\":\"Terms of Service\",\"details\":\"<div class=\\\"mb-5\\\">\\r\\n    <h5 class=\\\"mb-3\\\">What information do we collect?<\\/h5>\\r\\n    <p>We\\r\\n        gather data from you when you register on our site, submit a request,\\r\\n        buy any services, react to an overview, or round out a structure. At the\\r\\n        point when requesting any assistance or enrolling on our site, as\\r\\n        suitable, you might be approached to enter your: name, email address, or\\r\\n        telephone number. You may, nonetheless, visit our site anonymously.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h5 class=\\\"mb-3\\\">How do we protect your information?<\\/h5>\\r\\n    <p>All provided delicate\\/credit data is\\r\\n        sent through Stripe.<br \\/>After\\r\\n        an exchange, your private data (credit cards, social security numbers,\\r\\n        financials, and so on) won\'t be put away on our workers.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h5 class=\\\"mb-3\\\">Do we disclose any information to outside parties?<\\/h5>\\r\\n    <p>We\\r\\n        don\'t sell, exchange, or in any case, move to outside gatherings by and\\r\\n        by recognizable data. This does exclude confided-in outsiders who help\\r\\n        us in working our site, leading our business, or adjusting you since\\r\\n        those gatherings consent to keep this data private. We may likewise\\r\\n        deliver your data when we accept discharge is suitable to follow the\\r\\n        law, implement our site strategies, or ensure our own or others\' rights,\\r\\n        property, or wellbeing.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h5 class=\\\"mb-3\\\">Children\'s Online Privacy Protection Act Compliance<\\/h5>\\r\\n    <p>We\\r\\n        are consistent with the prerequisites of COPPA (Children\'s Online\\r\\n        Privacy Protection Act), we don\'t gather any data from anybody under 13\\r\\n        years old. Our site, items, and administrations are completely\\r\\n        coordinated to individuals who are in any event 13 years of age or more\\r\\n        established.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h5 class=\\\"mb-3\\\">\\r\\n        Changes to our Privacy Policy<\\/h5>\\r\\n    <p>If we decide to change our privacy\\r\\n        policy, we will post those changes on this page.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h5 class=\\\"mb-3\\\">How long we retain your information?<\\/h5>\\r\\n    <p>At\\r\\n        the point when you register for our site, we cycle and keep the\\r\\n        information we have about you however long you don\'t erase the record or\\r\\n        withdraw yourself (subject to laws and guidelines).<\\/p>\\r\\n<\\/div>\\r\\n<div>\\r\\n    <h5 class=\\\"mb-3\\\">What we don\\u2019t do with your data<\\/h5>\\r\\n    <p>We\\r\\n        don\'t and will never share, unveil, sell, or in any case give your\\r\\n        information to different organizations for the promotion of their items\\r\\n        or administrations.<\\/p>\\r\\n<\\/div>\"}','{\"image\":\"6635d5d9618e71714804185.png\",\"description\":null,\"social_title\":null,\"social_description\":null,\"keywords\":null}','basic','terms-of-service','2021-06-09 08:51:18','2025-03-18 23:11:33'),(44,'maintenance.data','{\"description\":\"<div class=\\\"mb-5\\\" style=\\\"font-family: Nunito, sans-serif; margin-bottom: 3rem !important;\\\"><h3 class=\\\"mb-3\\\" style=\\\"text-align: center; font-weight: 600; line-height: 1.3; font-size: 24px; font-family: Exo, sans-serif;\\\"><font color=\\\"#ff0000\\\">THE SITE IS UNDER MAINTENANCE<\\/font><\\/h3><p class=\\\"font-18\\\" style=\\\"color: rgb(111, 111, 111); text-align: center; margin-right: 0px; margin-left: 0px; font-size: 18px !important;\\\">We\'re just tuning up a few things.We apologize for the inconvenience but Front is currently undergoing planned maintenance. Thanks for your patience.<\\/p><\\/div>\",\"image\":\"6603c203472ad1711522307.png\"}',NULL,NULL,NULL,'2020-07-04 23:42:52','2024-03-27 06:51:47'),(52,'blog.element','{\"has_image\":[\"1\"],\"title\":\"Exploring the Cryptocurrency Landscape: A Comprehensive Guide for Beginners.\",\"description\":\"<div>The landscape of service center automation has undergone a remarkable transformation over the past few decades,\\r\\n    shifting from reactive to proactive approaches. Initially, service centers operated on a reactive model, primarily\\r\\n    addressing issues only after they arose. This method often involved responding to customer complaints and\\r\\n    troubleshooting problems as they emerged, leading to higher levels of downtime and customer dissatisfaction. The\\r\\n    focus was largely on fixing problems rather than preventing them, which created a cycle of continuous reaction to\\r\\n    service issues.<\\/div>\\r\\n<div><br \\/><\\/div>\\r\\n<h6 class=\\\"m-0\\\">Shifting Paradigms: The Move Toward Proactive Service Models<\\/h6>\\r\\n<div>As technology advanced, the paradigm began to shift towards a more proactive approach. The rise of advanced data\\r\\n    analytics and machine learning techniques enabled service centers to anticipate potential issues before they\\r\\n    occurred. By analyzing historical data and recognizing patterns, service centers could now predict when equipment\\r\\n    might fail or when a system could encounter problems. This shift not only reduced the frequency of unexpected\\r\\n    disruptions but also improved overall operational efficiency. Predictive maintenance became a key feature of\\r\\n    proactive service centers, allowing them to schedule maintenance activities during non-peak hours and address issues\\r\\n    before they impacted the customer experience.<\\/div>\\r\\n<div><br \\/><\\/div>\\r\\n<blockquote style=\\\"font-style:italic;text-align:center;padding:20px;color:#464545;background:rgba(139,131,133,0.54);font-size:18px;border-left:4px solid rgb(223,52,89);\\\">\\r\\n    As technology continues to evolve, service centers are likely to adopt even more advanced and innovative solutions that enhance their ability to provide seamless and proactive service.<\\/blockquote>\\r\\n<h6 class=\\\"m-0\\\">Harnessing Data Analytics and Machine Learning for Predictive Maintenance<\\/h6>\\r\\n<div>This evolution was further accelerated by the integration of artificial intelligence (AI) and automation tools.\\r\\n    AI-driven systems can now monitor and analyze real-time data from various sources, providing insights into potential\\r\\n    issues and suggesting preventive measures. Automation tools facilitate swift responses to identified issues, often\\r\\n    without the need for human intervention. For instance, automated systems can initiate repairs or adjustments based\\r\\n    on predefined parameters, ensuring that minor issues are resolved before they escalate into significant problems.\\r\\n<\\/div>\\r\\n<div><br \\/><\\/div>\\r\\n<h6 class=\\\"m-0\\\">The Role of AI and Automation in Revolutionizing Service Center Operations<\\/h6>\\r\\n<div>The proactive approach not only enhances operational efficiency but also fosters a more positive customer\\r\\n    experience. By addressing potential issues before they impact customers, service centers can ensure a higher level\\r\\n    of service continuity and reliability. Customers benefit from fewer disruptions and a more streamlined experience,\\r\\n    leading to increased satisfaction and loyalty.<\\/div>\\r\\n<div><br \\/><\\/div>\\r\\n<h6 class=\\\"m-0\\\">Enhancing Customer Experience Through Proactive Service Strategies<\\/h6>\\r\\n<div>In essence, the evolution from a reactive to a proactive model in service center automation represents a\\r\\n    significant leap forward. It highlights the importance of leveraging advanced technologies to not only address\\r\\n    problems but to anticipate and prevent them, ultimately leading to a more efficient and customer-centric operation.\\r\\n    As technology continues to evolve, service centers will likely see even more sophisticated solutions that further\\r\\n    enhance their ability to provide seamless and proactive service.<\\/div>\\r\\n<div><br \\/><\\/div>\",\"image\":\"67d290bee76941741852862.png\"}',NULL,'basic','exploring-the-cryptocurrency-landscape-a-comprehensive-guide-for-beginners','2024-03-24 06:52:04','2025-03-19 01:59:58'),(55,'counter.content','{\"heading\":\"Latest Newsss\",\"subheading\":\"Lorem ipsum dolor sit, amet consectetur adipisicing elit. Doloribus necessitatibus repudiandae porro reprehenderit, beatae perferendis repellat quo ipsa omnis, vitae!\"}',NULL,'basic','','2024-04-21 01