LOCK TABLES `notification_templates` WRITE;
/*!40000 ALTER TABLE `notification_templates` DISABLE KEYS */;
INSERT INTO `notification_templates` VALUES (1,'BAL_ADD','Balance - Added','Your Account has been Credited','{{site_name}} - Balance Added','<div>We\'re writing to inform you that an amount of {{amount}} {{site_currency}} has been successfully added to your account.</div><div><br></div><div>Here are the details of the transaction:</div><div><br></div><div><b>Transaction Number: </b>{{trx}}</div><div><b>Current Balance:</b> {{post_balance}} {{site_currency}}</div><div><b>Admin Note:</b> {{remark}}</div><div><br></div><div>If you have any questions or require further assistance, please don\'t hesitate to contact us. We\'re here to assist you.</div>','We\'re writing to inform you that an amount of {{amount}} {{site_currency}} has been successfully added to your account.','{{amount}} {{site_currency}} has been successfully added to your account.','{\"trx\":\"Transaction number for the action\",\"amount\":\"Amount inserted by the admin\",\"remark\":\"Remark inserted by the admin\",\"post_balance\":\"Balance of the user after this transaction\"}',1,'{{site_name}} Finance',NULL,0,NULL,1,'2021-11-03 12:00:00','2024-05-25 00:49:44'),(2,'BAL_SUB','Balance - Subtracted','Your Account has been Debited','{{site_name}} - Balance Subtracted','<div>We wish to inform you that an amount of {{amount}} {{site_currency}} has been successfully deducted from your account.</div><div><br></div><div>Below are the details of the transaction:</div><div><br></div><div><b>Transaction Number:</b> {{trx}}</div><div><b>Current Balance: </b>{{post_balance}} {{site_currency}}</div><div><b>Admin Note:</b> {{remark}}</div><div><br></div><div>Should you require any further clarification or assistance, please do not hesitate to reach out to us. We are here to assist you in any way we can.</div><div><br></div><div>Thank you for your continued trust in {{site_name}}.</div>','We wish to inform you that an amount of {{amount}} {{site_currency}} has been successfully deducted from your account.','{{amount}} {{site_currency}} debited from your account.','{\"trx\":\"Transaction number for the action\",\"amount\":\"Amount inserted by the admin\",\"remark\":\"Remark inserted by the admin\",\"post_balance\":\"Balance of the user after this transaction\"}',1,'{{site_name}} Finance',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:17:48'),(3,'DEPOSIT_COMPLETE','Deposit - Automated - Successful','Deposit Completed Successfully','{{site_name}} - Deposit successful','<div>We\'re delighted to inform you that your deposit of {{amount}} {{site_currency}} via {{method_name}} has been completed.</div><div><br></div><div>Below, you\'ll find the details of your deposit:</div><div><br></div><div><b>Amount:</b> {{amount}} {{site_currency}}</div><div><b>Charge: </b>{{charge}} {{site_currency}}</div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>Received:</b> {{method_amount}} {{method_currency}}</div><div><b>Paid via:</b> {{method_name}}</div><div><b>Transaction Number:</b> {{trx}}</div><div><br></div><div>Your current balance stands at {{post_balance}} {{site_currency}}.</div><div><br></div><div>If you have any questions or need further assistance, feel free to reach out to our support team. We\'re here to assist you in any way we can.</div>','We\'re delighted to inform you that your deposit of {{amount}} {{site_currency}} via {{method_name}} has been completed.','Deposit Completed Successfully','{\"trx\":\"Transaction number for the deposit\",\"amount\":\"Amount inserted by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the deposit method\",\"method_currency\":\"Currency of the deposit method\",\"method_amount\":\"Amount after conversion between base currency and method currency\",\"post_balance\":\"Balance of the user after this transaction\"}',1,'{{site_name}} Billing',NULL,1,NULL,1,'2021-11-03 12:00:00','2024-05-08 07:20:34'),(4,'DEPOSIT_APPROVE','Deposit - Manual - Approved','Deposit Request Approved','{{site_name}} - Deposit Request Approved','<div>We are pleased to inform you that your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been approved.</div><div><br></div><div>Here are the details of your deposit:</div><div><br></div><div><b>Amount:</b> {{amount}} {{site_currency}}</div><div><b>Charge: </b>{{charge}} {{site_currency}}</div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>Received: </b>{{method_amount}} {{method_currency}}</div><div><b>Paid via: </b>{{method_name}}</div><div><b>Transaction Number: </b>{{trx}}</div><div><br></div><div>Your current balance now stands at {{post_balance}} {{site_currency}}.</div><div><br></div><div>Should you have any questions or require further assistance, please feel free to contact our support team. We\'re here to help.</div>','We are pleased to inform you that your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been approved.','Deposit of {{amount}} {{site_currency}} via {{method_name}} has been approved.','{\"trx\":\"Transaction number for the deposit\",\"amount\":\"Amount inserted by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the deposit method\",\"method_currency\":\"Currency of the deposit method\",\"method_amount\":\"Amount after conversion between base currency and method currency\",\"post_balance\":\"Balance of the user after this transaction\"}',1,'{{site_name}} Billing',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:19:49'),(5,'DEPOSIT_REJECT','Deposit - Manual - Rejected','Deposit Request Rejected','{{site_name}} - Deposit Request Rejected','<div>We regret to inform you that your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been rejected.</div><div><br></div><div>Here are the details of the rejected deposit:</div><div><br></div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>Received:</b> {{method_amount}} {{method_currency}}</div><div><b>Paid via:</b> {{method_name}}</div><div><b>Charge:</b> {{charge}}</div><div><b>Transaction Number:</b> {{trx}}</div><div><br></div><div>If you have any questions or need further clarification, please don\'t hesitate to contact us. We\'re here to assist you.</div><div><br></div><div>Rejection Reason:</div><div>{{rejection_message}}</div><div><br></div><div>Thank you for your understanding.</div>','We regret to inform you that your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been rejected.','Your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been rejected.','{\"trx\":\"Transaction number for the deposit\",\"amount\":\"Amount inserted by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the deposit method\",\"method_currency\":\"Currency of the deposit method\",\"method_amount\":\"Amount after conversion between base currency and method currency\",\"rejection_message\":\"Rejection message by the admin\"}',1,'{{site_name}} Billing',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:20:13'),(6,'DEPOSIT_REQUEST','Deposit - Manual - Requested','Deposit Request Submitted Successfully',NULL,'<div>We are pleased to confirm that your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been submitted successfully.</div><div><br></div><div>Below are the details of your deposit:</div><div><br></div><div><b>Amount:</b> {{amount}} {{site_currency}}</div><div><b>Charge:</b> {{charge}} {{site_currency}}</div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>Payable:</b> {{method_amount}} {{method_currency}}</div><div><b>Pay via: </b>{{method_name}}</div><div><b>Transaction Number:</b> {{trx}}</div><div><br></div><div>Should you have any questions or require further assistance, please feel free to reach out to our support team. We\'re here to assist you.</div>','We are pleased to confirm that your deposit request of {{amount}} {{site_currency}} via {{method_name}} has been submitted successfully.','Your deposit request of {{amount}} {{site_currency}} via {{method_name}} submitted successfully.','{\"trx\":\"Transaction number for the deposit\",\"amount\":\"Amount inserted by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the deposit method\",\"method_currency\":\"Currency of the deposit method\",\"method_amount\":\"Amount after conversion between base currency and method currency\"}',1,'{{site_name}} Billing',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-04-25 03:27:42'),(7,'PASS_RESET_CODE','Password - Reset - Code','Password Reset','{{site_name}} Password Reset Code','<div>We\'ve received a request to reset the password for your account on <b>{{time}}</b>. The request originated from\r\n            the following IP address: <b>{{ip}}</b>, using <b>{{browser}}</b> on <b>{{operating_system}}</b>.\r\n    </div><br>\r\n    <div><span>To proceed with the password reset, please use the following account recovery code</span>: <span><b><font size=\"6\">{{code}}</font></b></span></div><br>\r\n    <div><span>If you did not initiate this password reset request, please disregard this message. Your account security\r\n            remains our top priority, and we advise you to take appropriate action if you suspect any unauthorized\r\n            access to your account.</span></div>','To proceed with the password reset, please use the following account recovery code: {{code}}','To proceed with the password reset, please use the following account recovery code: {{code}}','{\"code\":\"Verification code for password reset\",\"ip\":\"IP address of the user\",\"browser\":\"Browser of the user\",\"operating_system\":\"Operating system of the user\",\"time\":\"Time of the request\"}',1,'{{site_name}} Authentication Center',NULL,0,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:24:57'),(8,'PASS_RESET_DONE','Password - Reset - Confirmation','Password Reset Successful',NULL,'<div><div><span>We are writing to inform you that the password reset for your account was successful. This action was completed at {{time}} from the following browser</span>: <span>{{browser}}</span><span>on {{operating_system}}, with the IP address</span>: <span>{{ip}}</span>.</div><br><div><span>Your account security is our utmost priority, and we are committed to ensuring the safety of your information. If you did not initiate this password reset or notice any suspicious activity on your account, please contact our support team immediately for further assistance.</span></div></div>','We are writing to inform you that the password reset for your account was successful.','We are writing to inform you that the password reset for your account was successful.','{\"ip\":\"IP address of the user\",\"browser\":\"Browser of the user\",\"operating_system\":\"Operating system of the user\",\"time\":\"Time of the request\"}',1,'{{site_name}} Authentication Center',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-04-25 03:27:24'),(9,'ADMIN_SUPPORT_REPLY','Support - Reply','Re: {{ticket_subject}} - Ticket #{{ticket_id}}','{{site_name}} - Support Ticket Replied','<div>\r\n    <div><span>Thank you for reaching out to us regarding your support ticket with the subject</span>:\r\n        <span>\"{{ticket_subject}}\"&nbsp;</span><span>and ticket ID</span>: {{ticket_id}}.</div><br>\r\n    <div><span>We have carefully reviewed your inquiry, and we are pleased to provide you with the following\r\n            response</span><span>:</span></div><br>\r\n    <div>{{reply}}</div><br>\r\n    <div><span>If you have any further questions or need additional assistance, please feel free to reply by clicking on\r\n            the following link</span>: <a href=\"{{link}}\" title=\"\" target=\"_blank\">{{link}}</a><span>. This link will take you to\r\n            the ticket thread where you can provide further information or ask for clarification.</span></div><br>\r\n    <div><span>Thank you for your patience and cooperation as we worked to address your concerns.</span></div>\r\n</div>','Thank you for reaching out to us regarding your support ticket with the subject: \"{{ticket_subject}}\" and ticket ID: {{ticket_id}}. We have carefully reviewed your inquiry. To check the response, please go to the following link: {{link}}','Re: {{ticket_subject}} - Ticket #{{ticket_id}}','{\"ticket_id\":\"ID of the support ticket\",\"ticket_subject\":\"Subject  of the support ticket\",\"reply\":\"Reply made by the admin\",\"link\":\"URL to view the support ticket\"}',1,'{{site_name}} Support Team',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:26:06'),(10,'EVER_CODE','Verification - Email','Email Verification Code',NULL,'<div>\r\n    <div><span>Thank you for taking the time to verify your email address with us. Your email verification code\r\n            is</span>: <b><font size=\"6\">{{code}}</font></b></div><br>\r\n    <div><span>Please enter this code in the designated field on our platform to complete the verification\r\n            process.</span></div><br>\r\n    <div><span>If you did not request this verification code, please disregard this email. Your account security is our\r\n            top priority, and we advise you to take appropriate measures if you suspect any unauthorized access.</span>\r\n    </div><br>\r\n    <div><span>If you have any questions or encounter any issues during the verification process, please don\'t hesitate\r\n            to contact our support team for assistance.</span></div><br>\r\n    <div><span>Thank you for choosing us.</span></div>\r\n</div>','---','---','{\"code\":\"Email verification code\"}',1,'{{site_name}} Verification Center',NULL,0,NULL,0,'2021-11-03 12:00:00','2024-04-25 03:27:12'),(11,'SVER_CODE','Verification - SMS','Verify Your Mobile Number',NULL,'---','Your mobile verification code is {{code}}. Please enter this code in the appropriate field to verify your mobile number. If you did not request this code, please ignore this message.','---','{\"code\":\"SMS Verification Code\"}',0,'{{site_name}} Verification Center',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-04-25 03:27:03'),(12,'WITHDRAW_APPROVE','Withdraw - Approved','Withdrawal Confirmation: Your Request Processed Successfully','{{site_name}} - Withdrawal Request Approved','<div>We are writing to inform you that your withdrawal request of {{amount}} {{site_currency}} via {{method_name}} has been processed successfully.</div><div><br></div><div>Below are the details of your withdrawal:</div><div><br></div><div><b>Amount:</b> {{amount}} {{site_currency}}</div><div><b>Charge:</b> {{charge}} {{site_currency}}</div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>You will receive:</b> {{method_amount}} {{method_currency}}</div><div><b>Via:</b> {{method_name}}</div><div><b>Transaction Number:</b> {{trx}}</div><div><br></div><hr><div><br></div><div><b>Details of Processed Payment:</b></div><div>{{admin_details}}</div><div><br></div><div>Should you have any questions or require further assistance, feel free to reach out to our support team. We\'re here to help.</div>','We are writing to inform you that your withdrawal request of {{amount}} {{site_currency}} via {{method_name}} has been processed successfully.','Withdrawal Confirmation: Your Request Processed Successfully','{\"trx\":\"Transaction number for the withdraw\",\"amount\":\"Amount requested by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the withdraw method\",\"method_currency\":\"Currency of the withdraw method\",\"method_amount\":\"Amount after conversion between base currency and method currency\",\"admin_details\":\"Details provided by the admin\"}',1,'{{site_name}} Finance',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:26:37'),(13,'WITHDRAW_REJECT','Withdraw - Rejected','Withdrawal Request Rejected','{{site_name}} - Withdrawal Request Rejected','<div>We regret to inform you that your withdrawal request of {{amount}} {{site_currency}} via {{method_name}} has been rejected.</div><div><br></div><div>Here are the details of your withdrawal:</div><div><br></div><div><b>Amount:</b> {{amount}} {{site_currency}}</div><div><b>Charge:</b> {{charge}} {{site_currency}}</div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>Expected Amount:</b> {{method_amount}} {{method_currency}}</div><div><b>Via:</b> {{method_name}}</div><div><b>Transaction Number:</b> {{trx}}</div><div><br></div><hr><div><br></div><div><b>Refund Details:</b></div><div>{{amount}} {{site_currency}} has been refunded to your account, and your current balance is {{post_balance}} {{site_currency}}.</div><div><br></div><hr><div><br></div><div><b>Reason for Rejection:</b></div><div>{{admin_details}}</div><div><br></div><div>If you have any questions or concerns regarding this rejection or need further assistance, please do not hesitate to contact our support team. We apologize for any inconvenience this may have caused.</div>','We regret to inform you that your withdrawal request of {{amount}} {{site_currency}} via {{method_name}} has been rejected.','Withdrawal Request Rejected','{\"trx\":\"Transaction number for the withdraw\",\"amount\":\"Amount requested by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the withdraw method\",\"method_currency\":\"Currency of the withdraw method\",\"method_amount\":\"Amount after conversion between base currency and method currency\",\"post_balance\":\"Balance of the user after fter this action\",\"admin_details\":\"Rejection message by the admin\"}',1,'{{site_name}} Finance',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:26:55'),(14,'WITHDRAW_REQUEST','Withdraw - Requested','Withdrawal Request Confirmation','{{site_name}} - Requested for withdrawal','<div>We are pleased to inform you that your withdrawal request of {{amount}} {{site_currency}} via {{method_name}} has been submitted successfully.</div><div><br></div><div>Here are the details of your withdrawal:</div><div><br></div><div><b>Amount:</b> {{amount}} {{site_currency}}</div><div><b>Charge:</b> {{charge}} {{site_currency}}</div><div><b>Conversion Rate:</b> 1 {{site_currency}} = {{rate}} {{method_currency}}</div><div><b>Expected Amount:</b> {{method_amount}} {{method_currency}}</div><div><b>Via:</b> {{method_name}}</div><div><b>Transaction Number:</b> {{trx}}</div><div><br></div><div>Your current balance is {{post_balance}} {{site_currency}}.</div><div><br></div><div>Should you have any questions or require further assistance, feel free to reach out to our support team. We\'re here to help.</div>','We are pleased to inform you that your withdrawal request of {{amount}} {{site_currency}} via {{method_name}} has been submitted successfully.','Withdrawal request submitted successfully','{\"trx\":\"Transaction number for the withdraw\",\"amount\":\"Amount requested by the user\",\"charge\":\"Gateway charge set by the admin\",\"rate\":\"Conversion rate between base currency and method currency\",\"method_name\":\"Name of the withdraw method\",\"method_currency\":\"Currency of the withdraw method\",\"method_amount\":\"Amount after conversion between base currency and method currency\",\"post_balance\":\"Balance of the user after fter this transaction\"}',1,'{{site_name}} Finance',NULL,1,NULL,0,'2021-11-03 12:00:00','2024-05-08 07:27:20'),(15,'DEFAULT','Default Template','{{subject}}','{{subject}}','{{message}}','{{message}}','{{message}}','{\"subject\":\"Subject\",\"message\":\"Message\"}',1,NULL,NULL,1,NULL,1,'2019-09-14 13:14:22','2024-05-16 01:32:53'),(16,'KYC_APPROVE','KYC Approved','KYC Details has been approved','{{site_name}} - KYC Approved','<div><div><span>We are pleased to inform you that your Know Your Customer (KYC) information has been successfully reviewed and approved. This means that you are now eligible to conduct any payout operations within our system.</span></div><br><div><span>Your commitment to completing the KYC process promptly is greatly appreciated, as it helps us ensure the security and integrity of our platform for all users.</span></div><br><div><span>With your KYC verification now complete, you can proceed with confidence to carry out any payout transactions you require. Should you encounter any issues or have any questions along the way, please don\'t hesitate to reach out to our support team. We\'re here to assist you every step of the way.</span></div><br><div><span>Thank you once again for choosing {{site_name}} and for your cooperation in this matter.</span></div></div>','We are pleased to inform you that your Know Your Customer (KYC) information has been successfully reviewed and approved. This means that you are now eligible to conduct any payout operations within our system.','Your  Know Your Customer (KYC) information has been approved successfully','[]',1,'{{site_name}} Verification Center',NULL,1,NULL,0,NULL,'2024-05-08 07:23:57'),(17,'KYC_REJECT','KYC Rejected','KYC has been rejected','{{site_name}} - KYC Rejected','<div><div><span>We regret to inform you that the Know Your Customer (KYC) information provided has been reviewed and unfortunately, it has not met our verification standards. As a result, we are unable to approve your KYC submission at this time.</span></div><br><div><span>We understand that this news may be disappointing, and we want to assure you that we take these matters seriously to maintain the security and integrity of our platform.</span></div><br><div><span>Reasons for rejection may include discrepancies or incomplete information in the documentation provided. If you believe there has been a misunderstanding or if you would like further clarification on why your KYC was rejected, please don\'t hesitate to contact our support team.</span></div><br><div><span>We encourage you to review your submitted information and ensure that all details are accurate and up-to-date. Once any necessary adjustments have been made, you are welcome to resubmit your KYC information for review.</span></div><br><div><span>We apologize for any inconvenience this may cause and appreciate your understanding and cooperation in this matter.</span></div><br><div>Rejection Reason:</div><div>{{reason}}</div><div><br></div><div><span>Thank you for your continued support and patience.</span></div></div>','We regret to inform you that the Know Your Customer (KYC) information provided has been reviewed and unfortunately, it has not met our verification standards. As a result, we are unable to approve your KYC submission at this time. We encourage you to review your submitted information and ensure that all details are accurate and up-to-date. Once any necessary adjustments have been made, you are welcome to resubmit your KYC information for review.','Your  Know Your Customer (KYC) information has been rejected','{\"reason\":\"Rejection Reason\"}',1,'{{site_name}} Verification Center',NULL,1,NULL,0,NULL,'2024-05-08 07:24:13'),(18,'BID_PLACED','Bid Placed','Bid has been placd successfully','{{site_name}} - Bid placed successfully','<div>Great news! A new freelancer has submitted a bid for your job [<b>{{title}}]</b>.</div><div><br></div><div>Freelancer: {{freelancer}}</div><div>Bid Amount: {{amount}}</div><div>Budget Type: {{budget_type}}</div>\r\n<div>Estimate Time: {{estimate}}</div><div><br></div><div>To review the bid and communicate with the freelancer.</div>','Great news! {{freelancer}} has submitted a bid for your job \'{{title}}\'.','A new freelancer has bid on your job {{title}}.','{\"amount\":\"Bid budget\",\"title\":\"Job title\",\"freelancer\":\"Bidded freelancer name\",\"budget_type\":\"Type of bid budget\"}',1,'{{site_name}} Verification Center',NULL,1,NULL,0,NULL,'2025-03-10 00:21:47'),(19,'BID_REJECTED','Bid rejected','Bid has been rejected successfully','{{site_name}} - Bid rejected successfully','<div>Oops! Your bid for {{title}} wasn’t selected this time. Don’t lose heart—there are plenty of opportunities ahead!</div><div>💼 Budget Type: {{budget_type}}&nbsp;&nbsp;</div><div>💰 Your Bid: {{bid_amount}}</div><div><br></div><div>Don\'t give up—more opportunities are just around the corner!</div>','Your bid for {{title}} wasn’t selected this time. Don’t lose heart—there are plenty of opportunities ahead!\"','Rejected bid on your {{title}}.','{\"title\":\"Job post title\",\"budget_type\":\"Job budget type\",\"bid_amount\":\"Bid Amount for project\"}',1,'{{site_name}} Verification Center',NULL,1,NULL,0,NULL,'2025-03-10 00:20:44'),(20,'BID_ACCEPTED','Bid accepted','Bid has been accepted successfully','{{site_name}} - Bid accepted successfully','<div>Congratulations! Your bid for the project titled [{{title}}] has been accepted by {{buyer}}.</div><div>💼 Budget Type: {{budget_type}}</div><div>💰Your Bid Amount: {{bid_amount}}</div><div>Estimated \r\n🕒 Time: {{estimated_time}}</div><div> ⏲️Assigned On: {{assigned_at}}</div><div><br></div><div>Best of luck with the project!</div><div><br></div>','Congratulations! Your bid for the project titled \"[{{title}}]\" has been accepted by {{buyer}}.','Accepted bid on your {{title}}.','{\"title\":\"Job post title\",\"budget_type\":\"Job budget type\",\"bid_amount\":\"Bid Amount for project\", \"buyer\":\"Job owner\", \"estimated_time\":\"Freelancer estimated time\", \"assigned_at\":\"Project assigned date by buyer\"}',1,'{{site_name}} Verification Center',NULL,1,NULL,0,NULL,'2025-03-10 00:21:17'),(21,'FREELANCER_INVITATION','Freelancer Invitation','{{site_n